     2| * Arduino Program for SmartPlant v2
     3| * Working with Arduino Uno R4 wifi
     4| * Sensors used: AHT10, TEMT6000, Capacitive Soil Moisture
     5| * Connection to Wifi and ThingSpeak using secrets.h
     6| */
     7|
     8|// Libraries
     9|#include <WiFiS3.h>             // WiFi library for arduino uno
    10|#include "arduino_secrets.h"    // Secrets file with credentials
    11|#include <Wire.h>               // Library for I2C
    12|#include <Adafruit_AHTX0.h>     // Library for AHT10 sensor.
    13|#include <ThingSpeak.h>         // Library for ThingSpeak
    14|
    15|// Pins used in the card by the sensors.
    16|const int LIGHT_PIN = A0;    // Pin for Light Sensor (TEMT6000) - Analog Pin
    17|const int SOIL_PIN = A1;     // Pin for Moisture Sensor - Analog Pin
    18|
    19|/*
    20| * Objects
    21| */
    22|Adafruit_AHTX0 aht;                     // AHT10 Object.
    23|
    24|/*
    25| * Setting up the WiFi credentials.
    26| */
    27|char ssid[] = SECRET_SSID;        // Network SSID (name) coming from secrests.h
    28|char pass[] = SECRET_PASS;        // Network password (use for WPA, or use as key for WEP) coming from secrets.h
    29|int status = WL_IDLE_STATUS;      // WiFi radio's status
    30|
    31|/*
    32| * Setting up the ThingSpeak credentials.
    33| */
    34|unsigned long myChannelNumber = SECRET_CH_ID;       // ThingSpeak Channel ID coming from secrets.h
    35|const char * myWriteAPIKey = SECRET_WRITE_APIKEY;   // ThingSpeak Write API Key coming from secrets.h
    36|String myStatus = "";                               // ThingSpeak status for channel
    37|WiFiClient client;                                  // WiFi client object for ThingSpeak connection
    38|
    39|/*
    40| * Calibration values for the sensors
    41| */
    42|
    43|/*
    44| * Soil Moisture Sensor:
    45| * ----------------------
    46|*/
    47|const int WaterValue = 210;        // According to calibration
    48|const int AirValue = 498;           // According to calibration
    49|
    50|/*
    51| * Global Variables
    52| */
    53|
    54|// AHT10 Sensor
    55|float humidity = 0.0;
    56|float temperature = 0.0;
    57|
    58|// Struct to hold multiple values from AHT10
    59|struct AHTReadings {
    60|    float temperature;
    61|    float humidity;
    62|};
    63|
    64|// LDR sensor (TEMT6000)
    65|float luxValue = 0.0;
    66|
    67|// Soil Moisture Sensor
    68|int soilMoistureValue = 0;
    69|int soilMoisturePercent = 0;
    70|
    71|/*
    72| * Time Frames in ms.
    73| */
    74|unsigned long previousMillis = 0;           // Stores last time the information was sent to thingspeak
    75|const int intervalStart = 5000;             // 5 seconds of welcoming message
    76|const int intervalPause = 3000;             // 3 seconds pause for clearing the screen
    77|const int intervalThingSpeak = 900000;      // 15 minutes interval for reporting to ThingSpeak
    78|
    79|/*
    80|* Debug mode
    81|*/
    82|const bool DEBUG_MODE = false;            // Debug mode for printing values to serial monitor
    83|
    84|
    85|/*
    86| * Setup of the program.
    87| */
    88|void setup() {
    89|    Serial.begin(9600);
    90|    
    91|    Serial.println("[SmartPlant v2] Welcome!");
    92|    delay(intervalStart);
    93|
    94|    // Connect to WiFi
    95|    Serial.println("[SmartPlant v2] Connecting WiFi. Please wait...");
    96|    connect_to_wifi();                  
    97|
    98|    // Sensors Initialization
    99|    Serial.println("[SmartPlant v2] Starting sensors. Please wait...");
   100|    
   101|    if (aht.begin()) {
   102|        Serial.println("[SmartPlant v2] AHT10 initialized successfully");
   103|    } else {
   104|        Serial.println("[SmartPlant v2] AHT10 initialization failed");
   105|    }
   106|
   107|    pinMode(LIGHT_PIN, INPUT);          // Light Pin Initialization
   108|    pinMode(SOIL_PIN, INPUT);           // Soil Pin Initialization
   109|    ThingSpeak.begin(client);           // ThingSpeak Initialization
   110|    delay(intervalStart);
   111|
   112|    // Init done
   113|    Serial.println("[SmartPlant v2] Setup done. Starting now...");
   114|    delay(intervalStart);              // Delay before moving on to loop
   115|    Serial.println("[SmartPlant v2] Reading sensors now...");
   116|}
   117|
   118|/*
   119| * Running loop.
   120| */
   121|void loop() {
   122|    // Check wifi connection. If not connected, try to reconnect.
   123|    if (status != WL_CONNECTED) {
   124|        Serial.println("[SmartPlant v2] Reconnecting WiFi. Please wait...");
   125|        connect_to_wifi();                  
   126|    }
   127|
   128|    // Reading sensor values
   129|    sensor_readings();    
   130|
   131|    if (DEBUG_MODE){
   132|        // Print to Serial for debugging
   133|        Serial.print("[SmartPlant v2] Data -> ");
   134|        Serial.print("Temp: "); Serial.print(temperature, 1); Serial.print("C | ");
   135|        Serial.print("Hum: ");  Serial.print(humidity, 1);    Serial.print("% | ");
   136|        Serial.print("Light: "); Serial.print(luxValue, 0);   Serial.print(" lux | ");
   137|        Serial.print("Soil Raw: "); Serial.print(soilMoistureValue); Serial.print(" | ");
   138|        Serial.print("Soil Moist: "); Serial.print(soilMoisturePercent); Serial.println("%");
   139|    }
   140|
   141|    // Sending sensor values to ThingSpeak
   142|    unsigned long currentMillis = millis();
   143|    if (currentMillis - previousMillis >= intervalThingSpeak) {
   144|        previousMillis = currentMillis; 
   145|        send_to_thing_speak();          
   146|    }
   147|
   148|    // End of loop
   149|    delay(intervalPause);
   150|}
   151|
   152|AHTReadings AHT10_READ(){
   153|    sensors_event_t hum, temp;
   154|    aht.getEvent(&hum, &temp);  // Read temperature and humidity
   155|
   156|    // Create a readings object and populate it
   157|    AHTReadings readings;
   158|    readings.temperature = temp.temperature;
   159|    readings.humidity = hum.relative_humidity;
   160|
   161|    return readings; // Return the whole object
   162|}
   163|
   164|float TEMT6000_READ(){
   165|    int analogValue = analogRead(LIGHT_PIN);        // Read TEMT6000 analog value (0-1023)
   166|    float voltage = analogValue * (5.0 / 1023.0);   // Convert to voltage (0-5V)
   167|    float lux = voltage * 200.0;  // Approximate conversion factor
   168|    return lux;
   169|}
   170|
   171|int SOIL_MOISTURE_READ(){
   172|    // Raw data from sensor
   173|    int soilValue = analogRead(SOIL_PIN);
   174|    return soilValue;
   175|}
   176|
   177|/*
   178| * Function: sensor_readings()
   179| */
   180|void sensor_readings() {
   181|    // Reading AHT10 values
   182|    AHTReadings data = AHT10_READ();
   183|    humidity = data.humidity;        
   184|    temperature = data.temperature;  
   185|
   186|    // Reading Light value
   187|    luxValue = TEMT6000_READ(); 
   188|
   189|    // Reading Soil Moisture value
   190|    soilMoistureValue = SOIL_MOISTURE_READ();
   191|    // Calculate moisture percentage according to calibration values
   192|    soilMoisturePercent = map(soilMoistureValue, AirValue, WaterValue, 0, 100);     
   193|}
   194|
   195|/* 
   196| * Function: send_to_thing_speak()
   197| */
   198|void send_to_thing_speak() {
   199|    // Set the fields with the values
   200|    ThingSpeak.setField(1, temperature);
   201|    ThingSpeak.setField(2, humidity);
   202|    ThingSpeak.setField(3, luxValue);
   203|    ThingSpeak.setField(4, soilMoisturePercent);
   204|    ThingSpeak.setField(5, soilMoistureValue);
   205|
   206|    // Set the status message
   207|    myStatus = "[SmartPlant v2] Data updated successfully!";
   208|    ThingSpeak.setStatus(myStatus);
   209|
   210|    // Write to ThingSpeak channel.
   211|    int x = ThingSpeak.writeFields(myChannelNumber, myWriteAPIKey);
   212|    delay(1000); // Give some time for the connection to complete
   213|    
   214|    if (DEBUG_MODE){
   215|        // Report result of connection to ThingSpeak
   216|        if (x == 200 || x == 0) {
   217|            Serial.println("[SmartPlant v2] ThingSpeak has been updated.");
   218|        }
   219|        else {
   220|            Serial.println("[SmartPlant v2] ThingSpeak has NOT been updated.");
   221|        }
   222|        delay(intervalPause);
   223|    }
   224|}
   225|
   226|/*
   227| * Function: connect_to_wifi()
   228| */
   229|void connect_to_wifi() {
   230|    // Check for the WiFi module
   231|    if (WiFi.status() == WL_NO_MODULE) {
   232|        // don't continue
   233|        while (true);
   234|    }
   235|    // Check wifi firmware version
   236|    String fv = WiFi.firmwareVersion();
   237|    if (fv < WIFI_FIRMWARE_LATEST_VERSION) {
   238|        Serial.println("[SmartPlant v2] Please upgrade the firmware");
   239|    }
   240|    // Attempt to connect to WiFi network:
   241|    while (status != WL_CONNECTED) {
   242|        Serial.print("[SmartPlant v2] Attempting to connect to WPA SSID: ");
   243|        Serial.println(ssid);
   244|        // Connect to WPA/WPA2 network:
   245|        status = WiFi.begin(ssid, pass);
   246|        // wait 10 seconds for connection:
   247|        delay(10000);
   248|    }
   249|    // Connected now. Print out success message.
   250|    Serial.println("[SmartPlant v2] WiFi Connected. Continuing...");
   251|    delay(intervalStart);
